const items = $input.all();
const activeBin = items.find(i => i.binary && i.binary.data && i.binary.data.fileName && i.binary.data.fileName.includes('active'));
const decisionsBin = items.find(i => i.binary && i.binary.data && i.binary.data.fileName && i.binary.data.fileName.includes('decisions'));

function decode(bin) {
  if (!bin || !bin.binary || !bin.binary.data || !bin.binary.data.data) return '';
  return Buffer.from(bin.binary.data.data, 'base64').toString('utf8');
}

const activeText = decode(activeBin);
const decisionsText = decode(decisionsBin);

function extractTop3(text) {
  if (!text) return Array.of('(active.md vuoto o non leggibile)');
  const lines = text.split(/\r?\n/);
  const out = [];
  let inHigh = false;
  for (const line of lines) {
    if (/^##\s+.*Alta priorit/i.test(line)) { inHigh = true; continue; }
    if (inHigh && /^##\s+/.test(line)) break;
    if (inHigh && /^\s*\d+\.\s+\*\*/.test(line)) {
      out.push(line.replace(/^\s*\d+\.\s+/, ''));
      if (out.length >= 3) break;
    }
  }
  return out.length ? out : Array.of('(nessuna priorità alta trovata)');
}

const priorities = extractTop3(activeText);
const today = new Date().toLocaleDateString('it-IT', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const body = [
  `# Briefing — ${today}`,
  '',
  '## Top 3 priorità',
  ...priorities.map((p, i) => `${i + 1}. ${p}`),
  '',
  '## Reminder decisioni chiave',
  decisionsText ? decisionsText.split(/\r?\n/).slice(0, 12).join('\n') : '(decisions.md non disponibile)',
  '',
  '---',
  'Fonte: ~/todos/active.md + ~/memory/decisions.md',
  'Generato da n8n workflow morning-briefing alle 08:00.'
].join('\n');

const subject = `Briefing ${today.split(',')[0]} — Top 3 priorità`;

return [{ json: { subject, body, generatedAt: new Date().toISOString() } }];
